class Solution:
    def numRollsToTarget(self, n: int, k: int, target: int) -> int:
        MOD = 10**9 + 7
        dp = [0] * (target + 1)
        dp[0] = 1
        for _ in range(n):
            next_dp = [0] * (target + 1)
            for j in range(target + 1):
                if dp[j] > 0:
                    for face in range(1, k + 1):
                        if j + face <= target:
                            next_dp[j + face] = (next_dp[j + face] + dp[j]) % MOD
            dp = next_dp
        return dp[target]
```
